public boolean evenlySpaced(int a, int b, int c) {
    // Determine the smallest, middle, and largest values among the three inputs.
    if (a <= b && a <= c) {
        if (b <= c) {
            // a is smallest, b is middle, c is largest
            int diff1 = b - a;
            int diff2 = c - b;
            return diff1 == diff2;
        } else {
            // a is smallest, c is middle, b is largest
            int diff1 = c - a;
            int diff2 = b - c;
            return diff1 == diff2;
        }
    } else if (b <= a && b <= c) {
        if (a <= c) {
            // b is smallest, a is middle, c is largest
            int diff1 = a - b;
            int diff2 = c - a;
            return diff1 == diff2;
        } else {
            // b is smallest, c is middle, a is largest
            int diff1 = c - b;
            int diff2 = a - c;
            return diff1 == diff2;
        }
    } else {
        // c is smallest, a is middle, b is largest
        int diff1 = a - c;
        int diff2 = b - a;
        return diff1 == diff2;
    }
}

