public int round10(int num)
{
    int rightmostDigit = num % 10;
    if (rightmostDigit >= 5) {
        return num + (10 - rightmostDigit);
    } else {
        return num - rightmostDigit;
    }
}

public int[] tenRun(int[] nums) {
    if(nums == null || nums.length == 0){
        return nums;
    }

    int n = nums.length;
    for(int i = 0; i < n; i++){
        if(nums[i] % 10 == 0){
            int value = nums[i];
            for(int j = i + 1; j < n; j++){
                if(nums[j] % 10 == 0){
                    break;
                }
                nums[j] = value;
            }
        }
    }
    return nums;
}

